import Navbar from './Navbar'

const Layout = ({ children }) => (
 <>
    <style>{style}</style>
    <div className='wrapper'>
        <Title/>
        <Navbar/>
        {children}
    </div>
 </>
)

const style = `
    * {
      font-family:Roboto;
    }
    .wrapper {
        width:70vw;
        margin:auto;
    }
    ol {
        padding-left:1rem;
    }
`

export default Layout

const Title = () => (
    <div>
      <h1 className='title'>Wenuwake</h1>
      <div className='sub-title'>
        Portfolio website of Jithin KS
      </div>
    </div>
  )
